# tests/conftest.py — shared fixtures for integration tests
import pytest
from fastapi.testclient import TestClient
from sqlalchemy import create_engine, text
from sqlalchemy.orm import sessionmaker
from unittest.mock import patch, MagicMock

from app.main import app
from app.database import Base, get_db

POSTGRES_TEST_URL = "postgresql://test:test@localhost:5432/testdb"

engine = create_engine(POSTGRES_TEST_URL, echo=False)
TestingSessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)


@pytest.fixture(scope="session", autouse=True)
def create_tables():
    """Create all tables once per test session, drop on teardown."""
    Base.metadata.create_all(bind=engine)
    yield
    Base.metadata.drop_all(bind=engine)


@pytest.fixture()
def db_session(create_tables):
    """Each test gets a transaction that rolls back after the test completes."""
    connection = engine.connect()
    transaction = connection.begin()
    session = TestingSessionLocal(bind=connection)
    try:
        yield session
    finally:
        session.close()
        transaction.rollback()
        connection.close()


@pytest.fixture()
def client(db_session):
    """FastAPI TestClient wired to the test DB session via DI override."""
    def override_get_db():
        try:
            yield db_session
        finally:
            pass

    app.dependency_overrides[get_db] = override_get_db
    with TestClient(app, raise_server_exceptions=True) as c:
        yield c
    app.dependency_overrides.clear()


@pytest.fixture()
def mock_llm():
    """Stub the LLM HTTP call so integration tests never hit the real API."""
    with patch("app.agent.llm_client.complete") as mock:
        mock.return_value = {
            "id": "stub-001",
            "content": "I will use the search tool to find information.",
            "tool_calls": [
                {"name": "web_search", "args": {"query": "agentic AI testing"}}
            ],
            "usage": {"input_tokens": 120, "output_tokens": 45},
        }
        yield mock


@pytest.fixture()
def auth_headers():
    """Valid bearer token headers for protected endpoints."""
    return {"Authorization": "Bearer test-token-abc123"}
